void cursorUsuarioMenu(int x, int y) {
	Console::SetCursorPosition(x, y);
}
void coloresUsuarioMenu(int c) {
	switch (c)
	{
	case 0:  Console::ForegroundColor = ConsoleColor::Black; break;
	case 1:  Console::ForegroundColor = ConsoleColor::White; break;
	case 2:  Console::ForegroundColor = ConsoleColor::Cyan; break;
	case 3:  Console::ForegroundColor = ConsoleColor::Yellow; break;
	case 4:  Console::ForegroundColor = ConsoleColor::DarkRed; break;
	case 5:  Console::ForegroundColor = ConsoleColor::Green; break;
	case 6:  Console::ForegroundColor = ConsoleColor::DarkGray; break;
	}
}
void dibujarUsuarioMenu() {
	for (int i = 0; i < PRESENTACION_ALTO; i++) {
		for (int c = 0; c < PRESENTACION_ANCHO; c++) {
			if (fondoUsuarioMenu[i][c] == 0) coloresUsuarioMenu(0);
			if (fondoUsuarioMenu[i][c] == 1) coloresUsuarioMenu(1);
			if (fondoUsuarioMenu[i][c] == 2) coloresUsuarioMenu(2);
			if (fondoUsuarioMenu[i][c] == 3) coloresUsuarioMenu(3);
			if (fondoUsuarioMenu[i][c] == 4) coloresUsuarioMenu(4);
			if (fondoUsuarioMenu[i][c] == 5) coloresUsuarioMenu(5);
			if (fondoUsuarioMenu[i][c] == 6) coloresUsuarioMenu(6);
			cursorUsuarioMenu(c, i); cout << (char)219;
		}
	}
	Console::ForegroundColor = ConsoleColor::White;

}
